define('taoProctoring/controller/Delivery/testTakers',['jquery', 'i18n', 'helpers', 'layout/loading-bar', 'util/encode', 'ui/feedback', 'taoProctoring/component/breadcrumbs', 'ui/datatable'], function ($, __, helpers, loadingBar, encode, feedback, breadcrumbsFactory) {
  'use strict';
  var cssScope = '.delivery-testtakers';
  loadingBar.start();
  var proctorDeliveryAssignCtlr = {
    start: function start() {
      var $container = $(cssScope);
      var $list = $container.find('.list');
      var crumbs = $container.data('breadcrumbs');
      var dataset = $container.data('set');
      var deliveryId = $container.data('delivery');
      var testCenterId = $container.data('testcenter');
      var serviceUrl = helpers._url('availableTestTakers', 'Delivery', 'taoProctoring', {
        delivery: deliveryId,
        testCenter: testCenterId
      });
      var assignUrl = helpers._url('assignTestTakers', 'Delivery', 'taoProctoring', {
        delivery: deliveryId,
        testCenter: testCenterId
      });
      var managerUrl = helpers._url('manage', 'Delivery', 'taoProctoring', {
        delivery: deliveryId,
        testCenter: testCenterId
      });
      var bc = breadcrumbsFactory($container, crumbs);
      var assign = function assign(selection) {
        if (selection && selection.length) {
          loadingBar.start();
          $.ajax({
            url: assignUrl,
            data: {
              testtaker: selection
            },
            dataType: 'json',
            type: 'POST',
            error: function error() {
              loadingBar.stop();
            }
          }).done(function (response) {
            loadingBar.stop();
            if (response && response.success) {
              feedback().success(__('Test takers have been added'));
              window.location.href = managerUrl;
            } else {
              feedback().error(__('Something went wrong ...') + '<br>' + encode.html(response.error), {
                encodeHtml: false
              });
            }
          });
        }
      };
      $list.on('query.datatable', function () {
        loadingBar.start();
      }).on('load.datatable', function (event, response) {
        loadingBar.stop();
      }).datatable({
        url: serviceUrl,
        status: {
          empty: __('No available test takers to assign'),
          available: __('Available test takers'),
          loading: __('Loading')
        },
        tools: [{
          id: 'back',
          icon: 'left',
          title: __('Return to the session manager'),
          label: __('Back'),
          action: function action() {
            window.location.href = managerUrl;
          }
        }, {
          id: 'refresh',
          icon: 'reset',
          title: __('Refresh the page'),
          label: __('Refresh'),
          action: function action() {
            $list.datatable('refresh');
          }
        }, {
          id: 'assign',
          icon: 'add',
          title: __('Assign the selected test takers to the session'),
          label: __('Assign the selected test takers'),
          massAction: true,
          action: function action(selection) {
            assign(selection);
          }
        }],
        actions: [{
          id: 'assign',
          icon: 'add',
          title: __('Assign the test taker to the session'),
          action: function action(id) {
            assign([id]);
          }
        }],
        selectable: true,
        model: [{
          id: 'firstname',
          label: __('First name')
        }, {
          id: 'lastname',
          label: __('Last name')
        }, {
          id: 'identifier',
          label: __('Identifier')
        }]
      }, dataset);
    }
  };
  return proctorDeliveryAssignCtlr;
});
