define('taoProctoring/controller/DeliveryServer/awaiting',['lodash', 'jquery', 'i18n', 'helpers', 'layout/loading-bar', 'ui/dialog/alert', 'core/polling', 'taoQtiTest/testRunner/resumingStrategy/keepAfterResume', 'ui/dialog/confirm', 'tpl!taoProctoring/templates/deliveryServer/authorizationSuccess', 'tpl!taoProctoring/templates/deliveryServer/authorizationListBoxActions', 'tpl!taoProctoring/templates/deliveryServer/authorizationEntryPoint', 'util/clipboard', 'ui/component'], function (_, $, __, helpers, loadingBar, dialogAlert, polling, keepAfterResume, dialogConfirm, authSuccessTpl, listBoxActionsTpl, authorizationEntryPointTpl, clipboard) {
  'use strict';
  var refreshPolling = 10 * 1000;
  var cssScope = '.awaiting-authorization';
  var awaitingAuthorizationCtlr = {
    start: function start(config) {
      var $container = $(cssScope);
      var isAuthorizedUrl = helpers._url('isAuthorized', 'DeliveryServer', 'taoProctoring', {
        deliveryExecution: config.deliveryExecution
      });
      var runDeliveryUrl = config.runDeliveryUrl;
      var spaceEnterKeyCodes = [13, 32];
      $container.html(authorizationEntryPointTpl({
        label: config.deliveryLabel
      }));
      $container.find('.authorization-actions').html(listBoxActionsTpl({
        id: config.deliveryExecution,
        cancelable: config.cancelable
      }));
      var $content = $container.find('.authorization-status');
      var $proccedButton = $container.find('.js-proceed');
      var deliveryStarted = false;
      var runDelivery = () => {
        loadingBar.start();
        $.get(isAuthorizedUrl, result => {
          if (!result.success) {
            if (result.message) {
              dialogAlert(result.message, exit);
            } else {
              dialogAlert(__('Unexpected response'), exit);
            }
          } else if (result.authorized) {
            clipboard.clean();
            deliveryStarted = true;
            window.location.href = runDeliveryUrl;
          } else {
            dialogAlert(__('Unexpected response'), exit);
          }
        });
      };
      var isRunnable = () => {
        return !$container.hasClass('authorization-in-progress') && !deliveryStarted;
      };
      var authorized = () => {
        $content.html(authSuccessTpl({
          message: __('Authorized, you may proceed')
        }));
        loadingBar.stop();
        $container.addClass('authorization-granted').removeClass('authorization-in-progress');
        $proccedButton.removeClass('dissabled-action');
        $proccedButton.attr('aria-disabled', false);
      };
      var exit = () => {
        window.location.href = config.returnUrl;
      };
      $proccedButton.addClass('dissabled-action');
      $proccedButton.attr('aria-disabled', true);
      keepAfterResume().reset();
      loadingBar.start(false);
      $container.on('click', '.js-cancel', () => {
        dialogConfirm(__('Are you sure you want to end the test?'), function () {
          window.location.href = config.cancelUrl;
        });
      });
      $container.on('keyup', '.js-cancel', e => {
        if (spaceEnterKeyCodes.includes(e.which)) {
          dialogConfirm(__('Are you sure you want to end the test?'), function () {
            window.location.href = config.cancelUrl;
          });
        }
      });
      $container.on('click', '.js-proceed', () => {
        if (isRunnable()) {
          runDelivery();
        }
        return false;
      });
      $container.on('keyup', '.js-proceed', e => {
        if (spaceEnterKeyCodes.includes(e.which)) {
          if (isRunnable()) {
            runDelivery();
          }
        }
        return false;
      });
      polling({
        action: function action() {
          var async = this.async();
          $.get(isAuthorizedUrl, result => {
            var stop = false;
            if (!result.success) {
              stop = true;
              if (result.message) {
                dialogAlert(result.message, exit);
              } else {
                dialogAlert(__('Unexpected response'), exit);
              }
            } else if (result.authorized) {
              stop = true;
              authorized();
            }
            if (stop) {
              async.reject();
            } else {
              async.resolve();
            }
          });
        },
        interval: refreshPolling,
        autoStart: true
      }).next();
    }
  };
  return awaitingAuthorizationCtlr;
});
