define('taoProctoring/component/history/historyTable',['jquery', 'lodash', 'i18n', 'ui/component', 'ui/datatable'], function ($, _, __, component) {
  'use strict';
  var _defaults = {
    sortBy: 'timestamp',
    sortOrder: 'desc'
  };
  function renderDetails(details) {
    if (_.isArray(details)) {
      details = details.join('<br />');
    }
    return details;
  }
  function historyTableFactory(config, data) {
    var initConfig = _.defaults(config || {}, _defaults);
    var historyTable = {
      refresh: function refresh(params) {
        var $element;
        if (this.is('rendered')) {
          $element = this.getElement();
          if (params) {
            $element.datatable('options', {
              params: params
            });
          }
          $element.datatable('refresh');
        } else {
          if (params) {
            initConfig.params = _.merge(initConfig.params, params);
          }
        }
      }
    };
    return component(historyTable).on('render', function () {
      var self = this;
      var tools = [{
        id: 'refresh',
        icon: 'reset',
        title: __('Refresh the page'),
        label: __('Refresh'),
        action: function action() {
          self.refresh();
        }
      }];
      this.getElement().on('query.datatable', function () {
        self.trigger('loading');
      }).on('load.datatable', function () {
        self.trigger('loaded');
      }).on('error.datatable', function (e, err) {
        self.trigger('error', err);
      }).datatable({
        url: initConfig.service,
        params: initConfig.params,
        sortby: initConfig.sortBy,
        sortorder: initConfig.sortOrder,
        status: {
          empty: __('No history to display!'),
          available: __('Available history'),
          loading: __('Loading')
        },
        selectable: !!(initConfig.tools && _.find(initConfig.tools, {
          massAction: true
        })),
        tools: tools.concat(initConfig.tools || []),
        model: [{
          id: 'date',
          label: __('Date'),
          sortable: true
        }, {
          id: 'role',
          label: __('Role'),
          sortable: true
        }, {
          id: 'actor',
          label: __('Actor'),
          sortable: true
        }, {
          id: 'event',
          label: __('Event'),
          sortable: true
        }, {
          id: 'details',
          label: __('Details'),
          transform: renderDetails
        }, {
          id: 'context',
          label: __('Context'),
          transform: renderDetails
        }]
      }, data);
    }).init(initConfig);
  }
  return historyTableFactory;
});
