define('taoProctoring/component/breadcrumbs',['ui/breadcrumbs'], function (breadcrumbs) {
  'use strict';
  return function breadcrumbFactory($container, crumbs) {
    return breadcrumbs({
      breadcrumbs: crumbs,
      renderTo: $container.find('.header'),
      replace: true,
      cls: 'action-bar horizontal-action-bar'
    });
  };
});
