define('taoProctoring/component/activityMonitoring/currentAssessmentActivity/currentAssessmentActivity',['jquery', 'lodash', 'i18n', 'ui/component', 'tpl!taoProctoring/component/activityMonitoring/currentAssessmentActivity/currentAssessmentActivity'], function ($, _, __, component, tpl) {
  'use strict';
  var _defaults = {
    assessments: {
      awaiting: {
        container: 'awaiting-assessments',
        label: __('Awaiting'),
        value: 0
      },
      authorized: {
        container: 'authorized-but-not-started-assessments',
        label: __('Authorized'),
        value: 0
      },
      current: {
        container: 'current-assessments',
        label: __('Total Current Assessments'),
        value: 0
      },
      inProgress: {
        container: 'in-progress-assessments',
        label: __('In Progress'),
        value: 0
      },
      paused: {
        container: 'paused-assessments',
        label: __('Paused'),
        value: 0
      }
    }
  };
  function currentAssessmentActivityFactory(config) {
    config = config || {};
    return component({
      update: function update(data) {
        _.merge(this.config.assessments, data);
        _.forEach(this.config.assessments, function (val) {
          $('.' + val.container, this.getElement()).text(val.value);
        }, this);
      }
    }, _defaults).setTemplate(tpl).init(config);
  }
  return currentAssessmentActivityFactory;
});
